{json.dumps(parsed_doc.get(&#39;metadata&#39;, {}), ensure_ascii=False, indent=2)}&#34; } ] for img in parsed_doc[&#39;images&#39;]: content.append({ &#34;type&#34;: &#34;image&#34;, &#34;source&#34;: { &#34;type&#34;: &#34;base64&#34;, &#34;media_type&#34;: &#34;image/png&#34;, &#34;data&#34;: img[&#39;data&#39;] } }) messages.append({ &#34;role&#34;: &#34;user&#34;, &#34;content&#34;: content }) else: # 纯文本模式 text_content = f&#34;&#34;&#34; 目标MES系统Schema: {json.dumps(mes_schema, ensure_ascii=False, indent=2)} 文档内容: {parsed_doc.get(&#39;text_content&#39;, &#39;&#39;)} 表格数据: {json.dumps(parsed_doc.get(&#39;sheets&#39;, []), ensure_ascii=False, indent=2)} &#34;&#34;&#34; messages.append({ &#34;role&#34;: &#34;user&#34;, &#34;content&#34;: text_content }) # 调用Claude API response = self.client.messages.create( model=self.model, max_tokens=4096, system=system_prompt, messages=messages ) # 解析返回结果 result_text = response.content[0].text # 提取JSON（处理可能的markdown包装） if &#34;```json&#34; in result_text: result_text = result_text.split(&#34;```json&#34;)[1].split(&#34;```&#34;)[0] extraction_result = json.loads(result_text) return extraction_result def generate_transformation_code(self, extraction_result: Dict[str, Any], mes_schema: Dict[str, Any]) -&gt; str: &#34;&#34;&#34; 根据字段映射方案生成数据转换代码 Args: extraction_result: 字段提取和映射结果 mes_schema: 目标MES系统schema Returns: 生成的Python转换代码 &#34;&#34;&#34; prompt = f&#34;&#34;&#34; 请根据以下字段映射方案，生成Python数据转换函数。 字段映射: {json.dumps(extraction_result[&#39;field_mapping&#39;], ensure_ascii=False, indent=2)} 业务规则: {json.dumps(extraction_result.get(&#39;business_rules&#39;, []), ensure_ascii=False, indent=2)} 目标Schema: {json.dumps(mes_schema, ensure_ascii=False, indent=2)} 要求： 1. 生成一个transform_order函数，接受原始数据，返回MES格式数据 2. 包含完整的数据验证和类型转换 3. 处理可能的异常情况 4. 添加详细的注释 5. 使用type hints 6. 包含单元测试用例 请只返回可执行的Python代码，不要包含其他解释。 &#34;&#34;&#34; response = self.client.messages.create( model=self.model, max_tokens=4096, messages=[{ &#34;role&#34;: &#34;user&#34;, &#34;content&#34;: prompt }] ) code = response.content[0].text # 提取代码块 if &#34;```python&#34; in code: code = code.split(&#34;```python&#34;)[1].split(&#34;```&#34;)[0] return code.strip() # generated by AI 3. 人机协作验证节点 设计三个关键的人工验证节点：
