from typing import Dict, Any, List import json class AgentLoopOptimizer: &#34;&#34;&#34;Agent自优化循环&#34;&#34;&#34; def __init__(self, client: Anthropic, max_iterations: int = 3): self.client = client self.model = &#34;claude-3-5-sonnet-20241022&#34; self.max_iterations = max_iterations self.history: List[Dict[str, Any]] = [] def optimize(self, failed_step: str, feedback: str, context: Dict[str, Any]) -&gt; Dict[str, Any]: &#34;&#34;&#34; 根据人工反馈优化处理流程 Args: failed_step: 失败的步骤（field_mapping/code_generation/transformation） feedback: 人工反馈 context: 上下文信息（包含原始数据、之前的尝试等） Returns: 优化后的结果 &#34;&#34;&#34; # 记录历史 self.history.append({ &#39;step&#39;: failed_step, &#39;feedback&#39;: feedback, &#39;iteration&#39;: len(self.history) }) if len(self.history) &gt;= self.max_iterations: raise Exception(f&#34;达到最大迭代次数 {self.max_iterations}，需要人工介入&#34;) # 构建优化提示 optimization_prompt = self._build_optimization_prompt( failed_step, feedback, context ) # 调用AI重新处理 response = self.client.messages.create( model=self.model, max_tokens=4096, messages=[{ &#34;role&#34;: &#34;user&#34;, &#34;content&#34;: optimization_prompt }] ) result_text = response.content[0].text # 根据不同步骤解析结果 if failed_step == &#39;field_mapping&#39;: if &#34;```json&#34; in result_text: result_text = result_text.split(&#34;```json&#34;)[1].split(&#34;```&#34;)[0] return json.loads(result_text) elif failed_step == &#39;code_generation&#39;: if &#34;```python&#34; in result_text: result_text = result_text.split(&#34;```python&#34;)[1].split(&#34;```&#34;)[0] return result_text.strip() else: # transformation if &#34;```json&#34; in result_text: result_text = result_text.split(&#34;```json&#34;)[1].split(&#34;```&#34;)[0] return json.loads(result_text) def _build_optimization_prompt(self, failed_step: str, feedback: str, context: Dict[str, Any]) -&gt; str: &#34;&#34;&#34;构建优化提示词&#34;&#34;&#34; base_prompt = f&#34;&#34;&#34; 你之前的处理在&#34;{failed_step}&#34;步骤出现了问题。 人工反馈: {feedback} 历史尝试: {json.dumps(self.history, ensure_ascii=False, indent=2)} 上下文信息: {json.dumps(context, ensure_ascii=False, indent=2)} 请分析问题原因，并提供改进的解决方案。 &#34;&#34;&#34; if failed_step == &#39;field_mapping&#39;: base_prompt += &#34;&#34;&#34; 请重新生成字段映射方案，要求： 1. 仔细分析人工反馈，理解问题所在 2. 调整字段识别和映射逻辑 3. 提高对特殊格式的处理能力 4. 返回完整的字段映射JSON 返回格式同之前的字段映射方案。 &#34;&#34;&#34; elif failed_step == &#39;code_generation&#39;: base_prompt += &#34;&#34;&#34; 请重新生成数据转换代码，要求： 1. 修复代码中的逻辑错误 2. 改进数据验证和错误处理 3. 确保代码可以正确执行 4. 添加针对反馈问题的特殊处理 只返回Python代码，不要其他解释。 &#34;&#34;&#34; else: # transformation base_prompt += &#34;&#34;&#34; 请分析转换结果的问题，并提供修正方案： 1. 识别数据转换中的错误 2. 提供正确的转换逻辑 3. 说明如何避免类似问题 返回修正后的MES数据JSON。 &#34;&#34;&#34; return base_prompt # generated by AI 5. 完整工作流编排 将所有组件串联起来：
from typing import Dict, Any, Optional import json import logging class OrderNormalizationWorkflow: &#34;&#34;&#34;订单归一化工作流&#34;&#34;&#34; def __init__(self, api_key: str, mes_schema: Dict[str, Any], max_retries: int = 3): self.parser_factory = DocumentParserFactory() self.extraction_agent = OrderExtractionAgent(api_key) self.optimizer = AgentLoopOptimizer(self.extraction_agent.client, max_retries) self.mes_schema = mes_schema # 验证节点 self.field_verification = FieldMappingVerification() self.code_verification = CodeValidationVerification() self.output_verification = OutputVerification() # 日志 self.logger = logging.getLogger(__name__) def process_order(self, file_path: str) -&gt; Dict[str, Any]: &#34;&#34;&#34; 处理单个订单文档 Args: file_path: 订单文档路径 Returns: 处理结果 &#34;&#34;&#34; self.logger.info(f&#34;开始处理订单文档: {file_path}&#34;) # Step 1: 文档解析 self.logger.info(&#34;Step 1: 解析文档&#34;) parsed_doc = self.parser_factory.parse(file_path) self.logger.info(f&#34;文档类型: {parsed_doc[&#39;type&#39;]}&#34;) # Step 2: 信息提取与字段映射 self.logger.info(&#34;Step 2: 提取订单信息&#34;) extraction_result = self._extract_with_retry(parsed_doc) # Step 3: 人工验证字段映射 self.logger.info(&#34;Step 3: 人工验证字段映射&#34;) verification_result = self.field_verification.verify(extraction_result) if verification_result[&#39;status&#39;] == VerificationStatus.REJECTED: self.logger.warning(&#34;字段映射被拒绝，启动优化循环&#34;) extraction_result = self.optimizer.optimize( failed_step=&#39;field_mapping&#39;, feedback=verification_result[&#39;feedback&#39;], context={ &#39;parsed_doc&#39;: parsed_doc, &#39;extraction_result&#39;: extraction_result, &#39;mes_schema&#39;: self.mes_schema } ) # 重新验证 verification_result = self.field_verification.verify(extraction_result) extraction_result = verification_result[&#39;data&#39;] # Step 4: 生成转换代码 self.logger.info(&#34;Step 4: 生成数据转换代码&#34;) transformation_code = self._generate_code_with_retry(extraction_result) # Step 5: 人工验证代码 self.logger.info(&#34;Step 5: 人工验证转换代码&#34;) code_verification_result = self.code_verification.verify(transformation_code) if code_verification_result[&#39;status&#39;] == VerificationStatus.REJECTED: self.logger.warning(&#34;转换代码被拒绝，启动优化循环&#34;) transformation_code = self.optimizer.optimize( failed_step=&#39;code_generation&#39;, feedback=code_verification_result[&#39;feedback&#39;], context={ &#39;extraction_result&#39;: extraction_result, &#39;mes_schema&#39;: self.mes_schema, &#39;previous_code&#39;: transformation_code } ) # 重新验证 code_verification_result = self.code_verification.verify(transformation_code) transformation_code = code_verification_result[&#39;data&#39;] # Step 6: 执行转换 self.logger.info(&#34;Step 6: 执行数据转换&#34;) transformed_data = self._execute_transformation( transformation_code, parsed_doc, extraction_result ) # Step 7: 人工验证输出 self.logger.info(&#34;Step 7: 人工验证转换结果&#34;) output_verification_result = self.output_verification.verify( parsed_doc, transformed_data ) if output_verification_result[&#39;status&#39;] == VerificationStatus.REJECTED: self.logger.warning(&#34;转换结果被拒绝，启动优化循环&#34;) # 需要重新生成代码 transformation_code = self.optimizer.optimize( failed_step=&#39;transformation&#39;, feedback=output_verification_result[&#39;feedback&#39;], context={ &#39;extraction_result&#39;: extraction_result, &#39;transformation_code&#39;: transformation_code, &#39;transformed_data&#39;: transformed_data, &#39;mes_schema&#39;: self.mes_schema } ) # 重新执行和验证 transformed_data = self._execute_transformation( transformation_code, parsed_doc, extraction_result ) output_verification_result = self.output_verification.verify( parsed_doc, transformed_data ) final_data = output_verification_result[&#39;data&#39;] # Step 8: 写入MES系统 self.logger.info(&#34;Step 8: 写入MES系统&#34;) mes_result = self._write_to_mes(final_data) self.logger.info(&#34;订单处理完成&#34;) return { &#39;status&#39;: &#39;success&#39;, &#39;order_id&#39;: final_data.get(&#39;order_id&#39;), &#39;mes_result&#39;: mes_result, &#39;optimization_iterations&#39;: len(self.optimizer.history) } def _extract_with_retry(self, parsed_doc: Dict[str, Any]) -&gt; Dict[str, Any]: &#34;&#34;&#34;带重试的信息提取&#34;&#34;&#34; try: return self.extraction_agent.extract_order_info(parsed_doc, self.mes_schema) except Exception as e: self.logger.error(f&#34;信息提取失败: {e}&#34;) raise def _generate_code_with_retry(self, extraction_result: Dict[str, Any]) -&gt; str: &#34;&#34;&#34;带重试的代码生成&#34;&#34;&#34; try: return self.extraction_agent.generate_transformation_code( extraction_result, self.mes_schema ) except Exception as e: self.logger.error(f&#34;代码生成失败: {e}&#34;) raise def _execute_transformation(self, code: str, parsed_doc: Dict[str, Any], extraction_result: Dict[str, Any]) -&gt; Dict[str, Any]: &#34;&#34;&#34;执行转换代码&#34;&#34;&#34; # 创建执行环境 exec_globals = { &#39;parsed_doc&#39;: parsed_doc, &#39;extraction_result&#39;: extraction_result, &#39;json&#39;: json } # 执行代码 exec(code, exec_globals) # 调用transform_order函数 if &#39;transform_order&#39; not in exec_globals: raise Exception(&#34;生成的代码中未找到transform_order函数&#34;) transform_func = exec_globals[&#39;transform_order&#39;] # 执行转换 result = transform_func(parsed_doc, extraction_result) return result def _write_to_mes(self, data: Dict[str, Any]) -&gt; Dict[str, Any]: &#34;&#34;&#34;写入MES系统&#34;&#34;&#34; # 这里是与MES系统集成的接口 # 实际实现需要根据具体的MES系统API self.logger.info(&#34;调用MES系统API写入数据&#34;) # 示例：调用REST API # import requests # response = requests.post( # &#39;https://mes-system.com/api/orders&#39;, # json=data, # headers={&#39;Authorization&#39;: &#39;Bearer xxx&#39;} # ) # return response.json() # 这里返回模拟结果 return { &#39;success&#39;: True, &#39;order_id&#39;: data.get(&#39;order_id&#39;), &#39;mes_order_number&#39;: &#39;MES-2025-&#39; + data.get(&#39;order_id&#39;, &#39;UNKNOWN&#39;) } # generated by AI 实际应用案例 场景：多种格式的客户订单 某制造企业收到三类主要客户的订单：
